import { useMutation, useQueryClient } from "@tanstack/react-query";
import { getApiClient } from "../../../apiClientInstance";
import type { ApiClientError } from "../../../types/client";
import { actionPageQueryKeys } from "./queryKeys";
import type {
  LeadPageSubmissionResponse,
  LeadSubmissionRequest,
} from "./types";

type UseUpdateLeadProps = {
  onError?: (error: ApiClientError) => void;
  onSuccess?: (data: LeadPageSubmissionResponse) => void;
};

export const useUpdateLeadPage = ({
  onError,
  onSuccess,
}: UseUpdateLeadProps = {}) => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (leadSubmissionRequest: LeadSubmissionRequest) => {
      return getApiClient(false, "public").put<LeadPageSubmissionResponse>(
        "/submissions/lead",
        leadSubmissionRequest,
      );
    },
    onError: (error: ApiClientError) => {
      onError?.(error);
    },
    onSuccess: async (data) => {
      onSuccess?.(data);

      // Invalidate the commitment query to refetch updated data
      await queryClient.invalidateQueries({
        queryKey: actionPageQueryKeys.entity({
          namespace: "public",
          parameters: {
            leadId: data.id,
          },
        }).queryKey,
      });
    },
  });
};

